        # Block access to private IP ranges
        for ip in ips:
            if is_private_ip(ip):
                return result
    except (socket.gaierror, ValueError):
        # Invalid URL or hostname resolution failure
        return result

    # Step 2: Create secure SSL context and HTTPS handler
    context = ssl.create_default_context(cafile=certifi.where())
    https_handler = urllib.request.HTTPSHandler(context=context)

    # Step 3: Create secure opener with redirect checks and HTTPS handler
    opener = urllib.request.build_opener(SecureRedirectHandler(), https_handler)

    # Step 4: Fetch and process the webpage content
    try:
        with opener.open(page_url, timeout=10) as response:
            # Determine content encoding
            content_type = response.headers.get('Content-Type', '')
            encoding = 'utf-8'
            if 'charset=' in content_type:
                encoding = content_type.split('charset=')[-1].strip()

            # Read and decode content with error handling
            html_content = response.read().decode(encoding, errors='replace')
    except (urllib.error.HTTPError, urllib.error.URLError, ssl.SSLError, socket.timeout, ValueError):
        # Handle network errors, timeouts, and invalid responses
        return result

    # Step 5: Parse HTML to extract metadata
    parser = MetaParser()
    try:
        parser.feed(html_content)
    except Exception:
        # Gracefully handle parsing errors
        pass

    # Update result with parsed data
    if parser.title.strip():
        result['title'] = parser.title.strip()
    if parser.description is not None:
        result['description'] = parser.description

    return result
